    #[arg(short, long, value_parser=helper::parse_range, conflicts_with="signature")]
    signature_at: Option<Range<usize>>,
    input: PathBuf,
    #[arg(conflicts_with = "signature_at")]
    signature: Option<PathBuf>,
}

